1	/**
2	 * Calendar sync (background only). The durable, official "what changed" engine:
3	 * runs on a chrome.alarm, lists changes via a sync token, and maintains the set
4	 * of upcoming visitor (magic-address) events in storage.local. Drives:
5	 *  - post-save refresh of the open event (changedIds),
6	 *  - the visitor-event notification + toolbar badge (newMarked / count),
7	 *  - the side panel's "open from list" picker (listMarked).
8	 * No DOM. Reflects SAVED state only (pre-save edits are add-on-only — see
9	 * Planning-docs/2026-06-19_calendar_addon_vs_extension_capabilities.md).
10	 */
11	import { MAGIC_ADDRESS } from './config';
12	import { encodeEid, isMarked, listEvents } from './calendar';
13	import type { VisitorEventSummary } from './types';
14	
15	const SYNC_TOKEN_KEY = 'auxilio.syncToken';
16	const MARKED_KEY = 'auxilio.markedEvents';
17	/** Events the user has already issued passes for from this extension — keyed by
18	 *  eventId, value = when handled. A durable overlay over the marked set so a
19	 *  finished event stops badging/notifying/nudging instead of nagging until it
20	 *  ages out. Local-only signal: passes sent via the add-on or another device
21	 *  won't appear here (full cross-channel truth needs an engine status endpoint —
22	 *  deferred). Pruned by HANDLED_TTL_MS. */
23	const HANDLED_KEY = 'auxilio.handledEvents';
24	/** iCalUids the ENGINE reports already have an active pass — i.e. handled through
25	 *  ANY surface (add-on, another device), not just this extension. Overwritten on
26	 *  each status poll (NOT durable like HANDLED_KEY): if passes are later cancelled
27	 *  elsewhere, the next poll drops the uid and the event correctly resurfaces. */
28	const ENGINE_HANDLED_KEY = 'auxilio.engineHandled';
29	/** When the last FULL (tokenless) re-scan ran. Incremental sync only reports
30	 *  changes, so an event missed when its change was first consumed (e.g. a
31	 *  different magic address in an earlier build) is never re-examined until a full
32	 *  re-scan. We force one periodically + on install so the set self-heals. */
33	const LAST_FULL_KEY = 'auxilio.lastFullSync';
34	const PAST_GRACE_MS = 60 * 60_000; // keep events until 1h after they end
35	const HANDLED_TTL_MS = 30 * 24 * 60 * 60_000; // forget "handled" after 30 days
36	const FULL_RESYNC_INTERVAL_MS = 12 * 60 * 60_000; // re-scan the whole window twice a day
37	
38	type MarkedMap = Record<string, VisitorEventSummary>;
39	type HandledMap = Record<string, number>;
40	
41	async function readMarked(): Promise<MarkedMap> {
42	  const r = await chrome.storage.local.get(MARKED_KEY);
43	  return (r[MARKED_KEY] as MarkedMap) ?? {};
44	}
45	
46	async function readHandled(): Promise<HandledMap> {
47	  const r = await chrome.storage.local.get(HANDLED_KEY);
48	  return (r[HANDLED_KEY] as HandledMap) ?? {};
49	}
50	
51	/** Drop the sync token so the next sync does a full tokenless re-scan of the
52	 *  forward window. Called on install/update so a config change (e.g. the magic
53	 *  address) takes effect immediately instead of waiting for the periodic resync. */
54	export async function clearSyncToken(): Promise<void> {
55	  await chrome.storage.local.remove([SYNC_TOKEN_KEY, LAST_FULL_KEY]);
56	}
57	
58	/** Record that passes were issued for this event — drops it from every nudge
59	 *  surface (badge, banner, notification, picker) until it ages out. */
60	export async function markHandled(eventId: string): Promise<void> {
61	  if (!eventId) return;
62	  const handled = await readHandled();
63	  handled[eventId] = Date.now();
64	  await chrome.storage.local.set({ [HANDLED_KEY]: handled });
65	}
66	
67	export async function readEngineHandled(): Promise<Set<string>> {
68	  const r = await chrome.storage.local.get(ENGINE_HANDLED_KEY);
69	  return new Set((r[ENGINE_HANDLED_KEY] as string[]) ?? []);
70	}
71	
72	/** iCalUids of marked events that aren't LOCALLY handled — the candidate set to
73	 *  ask the engine about. Deliberately ignores engineHandled: we must keep asking
74	 *  about already-engine-handled events so a pass cancelled elsewhere is re-detected
75	 *  and the event resurfaces. */
76	export async function listPendingICalUids(): Promise<string[]> {
77	  const [marked, handled] = await Promise.all([readMarked(), readHandled()]);
78	  const uids = new Set<string>();
79	  for (const m of Object.values(marked)) {
80	    if (handled[m.eventId]) continue;
81	    if (m.iCalUid) uids.add(m.iCalUid);
82	  }
83	  return [...uids];
84	}
85	
86	/** Replace the engine-handled iCalUid set with the latest status answer. Overwrite
87	 *  (not merge) so events whose passes were cancelled elsewhere drop out and
88	 *  resurface. Lower-cased for case-insensitive matching against marked iCalUids. */
89	export async function setEngineHandled(iCalUids: string[]): Promise<void> {
90	  await chrome.storage.local.set({
91	    [ENGINE_HANDLED_KEY]: [...new Set(iCalUids.map((u) => u.toLowerCase()))],
92	  });
93	}
94	
95	export interface SyncResult {
96	  changedIds: Set<string>;
97	  newMarked: VisitorEventSummary[];
98	  /** Events seen this cycle that are no longer pending visitor events (deleted/
99	   *  cancelled). Lets the in-page nudge purge stale optimistic guesses. */
100	  cancelledIds: string[];
101	  markedCount: number;
102	}
103	
104	/** Coalesce concurrent syncs (the 1-minute alarm + on-demand LIST/SYNC_NOW) so
105	 *  they can't race on the shared sync token / marked map and lose an update — both
106	 *  read the same baseline, both write at the end, and the later write clobbers the
107	 *  earlier one (an event one run marked can vanish, and won't be re-reported once
108	 *  the token advances). One in-flight sync at a time removes that hazard. */
109	let inFlight: Promise<SyncResult> | null = null;
110	export function runSync(accessToken: string): Promise<SyncResult> {
111	  if (inFlight) return inFlight;
112	  inFlight = doRunSync(accessToken).finally(() => {
113	    inFlight = null;
114	  });
115	  return inFlight;
116	}
117	
118	/** Pull changes since the last sync; update the marked set; report deltas. */
119	async function doRunSync(accessToken: string): Promise<SyncResult> {
120	  const store = await chrome.storage.local.get([
121	    SYNC_TOKEN_KEY,
122	    MARKED_KEY,
123	    HANDLED_KEY,
124	    ENGINE_HANDLED_KEY,
125	    LAST_FULL_KEY,
126	  ]);
127	  const engineHandled = new Set((store[ENGINE_HANDLED_KEY] as string[]) ?? []);
128	  // The set we knew BEFORE this sync — the baseline for "what's genuinely new"
129	  // (so a full re-scan that re-discovers the whole window doesn't re-notify).
130	  const prevMarked = (store[MARKED_KEY] as MarkedMap) ?? {};
131	  const handled = (store[HANDLED_KEY] as HandledMap) ?? {};
132	  const lastFull = (store[LAST_FULL_KEY] as number) ?? 0;
133	
134	  let syncToken = store[SYNC_TOKEN_KEY] as string | undefined;
135	  // Force a periodic full re-scan: incremental sync never re-reports an event
136	  // whose change was already consumed, so a once-missed event (wrong magic
137	  // address in a past build, a transient attendee trim) would stay invisible
138	  // forever. Dropping the token re-evaluates the whole forward window.
139	  if (syncToken && Date.now() - lastFull > FULL_RESYNC_INTERVAL_MS) {
140	    syncToken = undefined;
141	  }
142	
143	  let resp = await listEvents(accessToken, { syncToken });
144	  if (resp.expired) {
145	    // Token stale → full resync from scratch.
146	    syncToken = undefined;
147	    resp = await listEvents(accessToken, {});
148	  }
149	  // A tokenless call re-scanned the full window; rebuild the set from scratch so
150	  // stale/no-longer-marked events drop out. Incremental carries the set forward.
151	  const fullSync = !syncToken;
152	  const marked: MarkedMap = fullSync ? {} : { ...prevMarked };
153	
154	  const changedIds = new Set<string>();
155	  const newMarked: VisitorEventSummary[] = [];
156	  const cancelledIds: string[] = [];
157	
158	  // Series we already tracked (any previously-marked instance) — so a newly
159	  // discovered later occurrence of a known recurring event, OR a full re-scan
160	  // that re-finds the whole window, doesn't fire a fresh notification.
161	  const knownSeries = new Set(
162	    Object.values(prevMarked).map((m) => m.seriesId ?? m.eventId),
163	  );
164	  // Series notified within THIS cycle — collapses an initial sync that discovers
165	  // dozens of weekly instances at once down to a single notification.
166	  const notifiedSeries = new Set<string>();
167	
168	  for (const ev of resp.items) {
169	    if (!ev.id) continue;
170	    changedIds.add(ev.id);
171	    const cancelled = ev.status === 'cancelled';
172	    const marked_ = isMarked(ev);
173	    // DIAGNOSTIC: the magic address is somewhere in this event's payload, yet
174	    // isMarked() didn't flag it — i.e. it's not a structured attendee email and
175	    // not in `location` (e.g. it's only in the description, or events.list
176	    // returned a trimmed attendee list). This is the signature of a primary-
177	    // calendar miss; the warning shows exactly what we got back.
178	    if (!marked_ && MAGIC_ADDRESS && JSON.stringify(ev).toLowerCase().includes(MAGIC_ADDRESS)) {
179	      console.warn(
180	        '[auxilio] sync MISS: magic address in payload but isMarked() is false',
181	        { id: ev.id, summary: ev.summary, location: ev.location, attendees: ev.attendees, status: ev.status },
182	      );
183	    }
184	    if (marked_ && !cancelled) {
185	      const seriesId = ev.recurringEventId || ev.id;
186	      const summary: VisitorEventSummary = {
187	        eid: encodeEid(ev.id, 'primary'),
188	        eventId: ev.id,
189	        iCalUid: ev.iCalUID ?? '',
190	        title: ev.summary || '(no title)',
191	        start: ev.start?.dateTime ?? ev.start?.date,
192	        seriesId,
193	      };
194	      // Notify only for a genuinely new, not-yet-handled occurrence of a series we
195	      // weren't already tracking — one alert per recurring series, not per
196	      // instance, and never for an event a full re-scan merely re-discovered.
197	      const newInstance = !prevMarked[ev.id] && !handled[ev.id];
198	      if (newInstance && !knownSeries.has(seriesId) && !notifiedSeries.has(seriesId)) {
199	        newMarked.push(summary);
200	        notifiedSeries.add(seriesId);
201	      }
202	      marked[ev.id] = summary;
203	    } else {
204	      // Cancelled (deleted) or no longer a visitor event → not pending. Report
205	      // it so any optimistic in-page nudge for it gets purged, and forget any
206	      // "handled" record so the id can't linger.
207	      if (cancelled || prevMarked[ev.id]) cancelledIds.push(ev.id);
208	      delete marked[ev.id];
209	      delete handled[ev.id];
210	    }
211	  }
212	
213	  // Prune events that are well past.
214	  const cutoff = Date.now() - PAST_GRACE_MS;
215	  for (const id of Object.keys(marked)) {
216	    const s = marked[id].start;
217	    if (s && Date.parse(s) < cutoff) delete marked[id];
218	  }
219	
220	  // Prune stale "handled" records so the overlay can't grow without bound.
221	  const handledCutoff = Date.now() - HANDLED_TTL_MS;
222	  for (const id of Object.keys(handled)) {
223	    if (handled[id] < handledCutoff) delete handled[id];
224	  }
225	
226	  // DIAGNOSTIC: one line per sync so a primary-calendar miss is obvious — did the
227	  // list even return the event (itemsReturned), and did anything end up marked?
228	  console.log('[auxilio] sync done', {
229	    mode: fullSync ? 'full' : 'incremental',
230	    magicAddress: MAGIC_ADDRESS,
231	    itemsReturned: resp.items.length,
232	    markedTotal: Object.keys(marked).length,
233	    newMarked: newMarked.length,
234	  });
235	
236	  await chrome.storage.local.set({
237	    [SYNC_TOKEN_KEY]: resp.nextSyncToken ?? syncToken,
238	    [MARKED_KEY]: marked,
239	    [HANDLED_KEY]: handled,
240	    // Stamp the full-resync clock only when we actually did one, so the periodic
241	    // re-scan fires on schedule regardless of how often incremental sync runs.
242	    ...(fullSync ? { [LAST_FULL_KEY]: Date.now() } : {}),
243	  });
244	
245	  // markedCount drives the toolbar badge — count distinct pending series (a
246	  // recurring event counts once, not once per occurrence), excluding events the
247	  // engine already handled elsewhere. Uses the engineHandled set from the start
248	  // of this sync; the post-sync status poll reconciles the badge if it changed.
249	  const pendingSeries = new Set<string>();
250	  for (const id of Object.keys(marked)) {
251	    if (handled[id]) continue;
252	    if (engineHandled.has((marked[id].iCalUid ?? '').toLowerCase())) continue;
253	    pendingSeries.add(marked[id].seriesId ?? id);
254	  }
255	  return { changedIds, newMarked, cancelledIds, markedCount: pendingSeries.size };
256	}
257	
258	/** Upcoming visitor events still needing passes, soonest first — for the panel's
259	 *  picker and the in-page nudge. Handled events are filtered out, and a recurring
260	 *  series collapses to its soonest pending occurrence (one row, not one per week). */
261	export async function listMarked(): Promise<VisitorEventSummary[]> {
262	  const [marked, handled, engineHandled] = await Promise.all([
263	    readMarked(),
264	    readHandled(),
265	    readEngineHandled(),
266	  ]);
267	  const bySeries = new Map<string, VisitorEventSummary>();
268	  for (const m of Object.values(marked)) {
269	    if (handled[m.eventId]) continue;
270	    if (engineHandled.has((m.iCalUid ?? '').toLowerCase())) continue;
271	    const key = m.seriesId ?? m.eventId;
272	    const existing = bySeries.get(key);
273	    if (!existing || (m.start ?? '~').localeCompare(existing.start ?? '~') < 0) {
274	      bySeries.set(key, m);
275	    }
276	  }
277	  return [...bySeries.values()].sort((a, b) =>
278	    (a.start ?? '').localeCompare(b.start ?? ''),
279	  );
280	}
281	
282	/** Is this event id currently a known visitor event? */
283	export async function isEventMarked(eventId: string): Promise<boolean> {
284	  const marked = await readMarked();
285	  return !!marked[eventId];
286	}
