1	/**
2	 * Calendar read (background only). Two jobs:
3	 *  1) resolve the canonical event for a given eid (events.get) — authoritative
4	 *     iCalUID + attendees for the side panel.
5	 *  2) list changes via a sync token (events.list) — the durable "what changed"
6	 *     API that drives post-save refresh + the visitor-event nudge/badge.
7	 * Calendar.events.readonly only.
8	 */
9	import { MAGIC_ADDRESS } from './config';
10	import type { ActiveEvent } from './types';
11	
12	/** `eid` is URL-safe base64 of "<eventId> <calendarId>" (calendarId optional). */
13	export function decodeEid(eid: string): { eventId: string; calendarId: string } | null {
14	  try {
15	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
16	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
17	    const decoded = atob(b64);
18	    const [eventId, calendarId] = decoded.split(' ');
19	    if (!eventId) return null;
20	    return { eventId, calendarId: calendarId || 'primary' };
21	  } catch {
22	    return null;
23	  }
24	}
25	
26	/** Inverse of decodeEid — build an eid the side panel can resolve. */
27	export function encodeEid(eventId: string, calendarId = 'primary'): string {
28	  const b64 = btoa(`${eventId} ${calendarId}`);
29	  return b64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
30	}
31	
32	export interface GCalEvent {
33	  id?: string;
34	  iCalUID?: string;
35	  status?: string;
36	  summary?: string;
37	  location?: string;
38	  description?: string;
39	  /** Present on instances of a recurring series (with singleEvents=true): the id
40	   *  of the parent series. Lets us treat a series as one nudge unit. */
41	  recurringEventId?: string;
42	  start?: { dateTime?: string; date?: string };
43	  end?: { dateTime?: string; date?: string };
44	  organizer?: { email?: string };
45	  attendees?: {
46	    email?: string;
47	    displayName?: string;
48	    resource?: boolean;
49	    self?: boolean;
50	    organizer?: boolean;
51	  }[];
52	}
53	
54	/** Is this a visitor event? (magic address among attendees or in the location.) */
55	export function isMarked(ev: GCalEvent): boolean {
56	  if (!MAGIC_ADDRESS) return false;
57	  const inAttendees = (ev.attendees ?? []).some(
58	    (a) => a.email?.toLowerCase() === MAGIC_ADDRESS,
59	  );
60	  const inLocation = (ev.location ?? '').toLowerCase().includes(MAGIC_ADDRESS);
61	  return inAttendees || inLocation;
62	}
63	
64	function startOf(ev: GCalEvent): string | undefined {
65	  return ev.start?.dateTime ?? ev.start?.date;
66	}
67	
68	async function getEvent(
69	  calendarId: string,
70	  eventId: string,
71	  accessToken: string,
72	): Promise<Response> {
73	  const url = new URL(
74	    `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(
75	      calendarId,
76	    )}/events/${encodeURIComponent(eventId)}`,
77	  );
78	  url.searchParams.set(
79	    'fields',
80	    'iCalUID,summary,location,description,start,end,organizer,attendees(email,displayName,resource,self,organizer)',
81	  );
82	  return fetch(url, { headers: { Authorization: `Bearer ${accessToken}` } });
83	}
84	
85	export async function fetchActiveEvent(
86	  eid: string,
87	  accessToken: string,
88	): Promise<ActiveEvent> {
89	  const dec = decodeEid(eid);
90	  if (!dec) throw new Error('Could not read the event id from this page.');
91	
92	  // Recurring chips carry an instance id ("<base>_<ts>"); events.get often 404s
93	  // on the instance, so also try the base id. And try `primary` in case the
94	  // decoded calendar id isn't directly fetchable.
95	  const baseId = dec.eventId.includes('_') ? dec.eventId.split('_')[0] : null;
96	  const candidates: { cal: string; id: string }[] = [
97	    { cal: dec.calendarId, id: dec.eventId },
98	    ...(dec.calendarId !== 'primary' ? [{ cal: 'primary', id: dec.eventId }] : []),
99	    ...(baseId ? [{ cal: dec.calendarId, id: baseId }] : []),
