49	export function VisitPanel() {
50	  // `storedEid` is what the content script is pointing us at (auto-follow). We
51	  // freeze the *displayed* `eid` while busy so following never switches the view
52	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
53	  const storedEid = useActiveEid();
54	  const snapshot = useActiveSnapshot();
55	  const [eid, setEid] = useState<string | null>(storedEid);
56	  const auth = useAuthStatus();
57	  // Picker fuels the "open from list" empty state (and graceful fallback).
58	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
59	  const resolve = useResolveEvent(eid);
60	  const event = resolve.data;
61	  const draft = useDraft(event);
62	  // Fill real names + photos for email-only guests in the background (People API).
63	  useResolveGuestNames(draft.data);
64	
65	  const patch = usePatchDraft(event?.iCalUid);
66	  const send = useSend(event?.iCalUid, event?.start, event?.end);
67	  const preview = usePreview(event?.iCalUid);
68	
69	  const [previewData, setPreviewData] = useState<{
70	    preview: PreviewResponse;
71	    recipient: string;
72	  } | null>(null);
73	  // Non-structural host edits (name/phone change, template switch) leave no roster
74	  // delta, so we track them against a BASELINE captured lazily — the first time the
75	  // host touches a given guest (or the template), we snapshot its pre-edit value.
76	  // Deriving "edited" as a diff against that baseline means a revert back to the
77	  // original clears it (button deactivates), and a background name resolution that
78	  // fills an UNtouched guest is never mistaken for an edit (it's not in the baseline).
79	  // Refs (not state) so capturing doesn't itself trigger a render; the patch that
80	  // follows re-renders and recomputes the diff. Cleared when the event changes or a
81	  // send succeeds (the draft then reflects reality).
82	  const editBaseline = useRef<Record<string, { name: string; phone: string }>>({});
83	  const templateBaseline = useRef<string | undefined>(undefined);
84	  const resetEditBaseline = () => {
85	    editBaseline.current = {};
86	    templateBaseline.current = undefined;
87	  };
88	  useEffect(resetEditBaseline, [event?.iCalUid]);
89	
90	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
91	  const busy = send.isPending || preview.isPending || !!previewData;
92	  useEffect(() => {
93	    if (!busy) setEid(storedEid);
94	  }, [storedEid, busy]);
95	
96	  // Post-save refresh: the background sync poll broadcasts when the active event
97	  // changed on the server (no DOM); refetch so the roster reflects saved state.
98	  const qc = useQueryClient();
99	  useEffect(() => {
100	    const listener = (msg: { type?: string }) => {
101	      if (msg?.type === REFRESH_ACTIVE) {
102	        qc.invalidateQueries({ queryKey: ['resolve'] });
103	        qc.invalidateQueries({ queryKey: ['draft'] });
104	      }
105	    };
106	    chrome.runtime.onMessage.addListener(listener);
107	    return () => chrome.runtime.onMessage.removeListener(listener);
108	  }, [qc]);
109	
110	  // Back → clear the active event/snapshot, returning to the home list.
111	  const clearActive = () =>
112	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
113	  // Show Back in every screen except the pure home (no event, no snapshot).
114	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
115	
116	  // ---- gating states ----
117	  if (!eid) {
118	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
119	    // address) → preview the detected guests + prompt to save.
120	    if (snapshot?.magicPresent) {
121	      return (
122	        <Shell onBack={back}>
123	          <NoticeState
124	            title="Save the event to issue passes"
125	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
126	            guests={snapshot.guestEmails}
127	          />
128	        </Shell>
129	      );
130	    }
131	    return (
132	      <Shell>
133	        <EmptyState
134	          auth={auth.data}
135	          events={visitorEvents.data}
136	          loading={visitorEvents.isLoading}
137	          onPick={(ev) => {
138	            // Just point the panel at the picked event — no tab navigation. Use
139	            // "Open in Calendar" in the summary to jump to it explicitly.
140	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
141	          }}
142	        />
143	      </Shell>
144	    );
145	  }
146	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
147	    return <Shell onBack={back}><SignInGate /></Shell>;
148	  }
149	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
150	  if (resolve.isError) {
151	    const msg = (resolve.error as Error).message;
152	    if (msg === 'NOT_SAVED') {
153	      return (
154	        <Shell onBack={back}>
155	          <NoticeState
156	            title="Save the event to issue passes"
157	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
158	            onRetry={() => resolve.refetch()}
159	            guests={snapshot?.guestEmails}
160	          />
161	        </Shell>
162	      );
163	    }
164	    return (
165	      <Shell onBack={back}>
166	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
167	      </Shell>
168	    );
169	  }
170	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
171	  // skeleton forever). Surface it instead of hanging.
172	  if (event && !event.iCalUid) {
173	    return (
174	      <Shell onBack={back}>
175	        <NoticeState
176	          title="Can’t register from this event"
177	          body="This event has no calendar UID yet. This usually means it is not fully saved. Save it in Google Calendar and try again."
178	          onRetry={() => resolve.refetch()}
179	        />
180	      </Shell>
181	    );
182	  }
183	  if (draft.isError) {
184	    return (
185	      <Shell onBack={back}>
186	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
187	      </Shell>
188	    );
189	  }
190	  if (!draft.data) {
191	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
192	  }
193	
194	  const data = draft.data;
195	  const included = data.roster.filter((g) => g.include);
196	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
197	
198	  const templates = data.emailTemplates;
199	  // One template for the whole event (engine stores per-guest; we set all guests
200	  // to the chosen key).
201	  const currentTemplate =
202	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
203	    templates.find((t) => t.isDefault)?.key ??
204	    templates[0]?.key;
205	
206	  // What's actually pending. A new/uninvited guest still to get a pass, or a sent
207	  // guest toggled off (a pending revoke), is a STRUCTURAL change visible in the
208	  // roster (and reverts cleanly because it's recomputed here every render).
209	  const pendingNew = data.roster.filter(
210	    (g) => g.include && g.status !== 'sent' && g.status !== 'cancelled',
211	  );
212	  const pendingCancel = data.roster.filter((g) => g.status === 'sent' && !g.include);
213	
214	  // Non-structural edits: a guest whose name/phone now differs from its captured
215	  // baseline, or a template switched away from its baseline. Reverting to the
216	  // baseline value makes this false again.
217	  const edited =
218	    data.roster.some((g) => {
219	      const b = editBaseline.current[g.email];
220	      return b && ((g.name ?? '') !== b.name || (g.phone ?? '') !== b.phone);
221	    }) ||
222	    (templateBaseline.current !== undefined && currentTemplate !== templateBaseline.current);
223	
224	  const hasChanges = pendingNew.length > 0 || pendingCancel.length > 0 || edited;
225	  // Already-issued event with literally nothing to do → no point re-sending.
226	  const nothingToDo = data.materialized && !hasChanges;
227	
228	  const patchGuest = (email: string, edit: Record<string, unknown>) => {
229	    // An include toggle is STRUCTURAL (pendingNew/pendingCancel) — no baseline needed.
230	    // For a name/phone edit, snapshot this guest's PRE-edit values the first time it's
231	    // touched, so a later revert (or a background name fill on an untouched guest)
232	    // diffs correctly.
233	    if ('name' in edit || 'phone' in edit) {
234	      if (!(email in editBaseline.current)) {
235	        const g = data.roster.find((x) => x.email === email);
236	        if (g) editBaseline.current[email] = { name: g.name ?? '', phone: g.phone ?? '' };
237	      }
238	    }
239	    patch.mutate({ guests: [{ email, ...edit }] });
240	  };
241	
242	  const setEventTemplate = (key: string) => {
243	    // Snapshot the effective template before the first switch, so picking the
244	    // original template back clears the diff.
245	    if (templateBaseline.current === undefined) templateBaseline.current = currentTemplate;
246	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
247	  };
248	
249	  // Review & send: render the real email for a representative included guest,
250	  // then Send/Cancel from the preview.
251	  const reviewEmail = included[0]?.email;
252	  const openReview = () => {
253	    if (!reviewEmail) return;
254	    preview.mutate(reviewEmail, {
255	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
256	    });
257	  };
258	
259	  // First send needs at least one included guest; an already-issued event needs a
260	  // real pending change — otherwise the button is irrelevant and stays disabled.
261	  const canSend =
262	    !send.isPending && (data.materialized ? hasChanges : included.length > 0);
263	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
264	
265	  return (
266	    <Shell onBack={back}>
267	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
268	        {/* Event summary */}
269	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
270	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
271	          {event?.start && (
272	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
273	              <Clock size={15} strokeWidth={2} />
274	              {formatWhen(event.start, event.end)}
275	            </div>
276	          )}
277	          {event?.rooms && event.rooms.length > 0 && (
278	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
279	              <DoorOpen size={15} strokeWidth={2} />
280	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
281	            </div>
282	          )}
283	          {event?.description && (
284	            <div
285	              className="type-label-sm text-muted"
286	              style={{
287	                whiteSpace: 'pre-wrap',
288	                maxHeight: 72,
289	                overflow: 'hidden',
290	                borderTop: '1px solid var(--color-outline-variant)',
291	                paddingTop: 'var(--space-sm)',
292	              }}
293	            >
294	              {event.description}
295	            </div>
296	          )}
297	          {eid && (
298	            <Button
299	              variant="text"
300	              icon={<ExternalLink size={16} strokeWidth={2} />}
301	              onClick={() => void rpc({ type: 'NAVIGATE_TO_EVENT', eid })}
302	              // Negative left margin = the text button's own horizontal padding,
303	              // so the label optically aligns to the card edge while the hit area
304	              // and hover state layer stay intact (MD3 text-button placement).
305	              style={{ justifySelf: 'start', marginLeft: 'calc(-1 * var(--space-md))' }}
306	            >
307	              Open in Calendar
308	            </Button>
309	          )}
310	          {templates.length >= 2 && (
311	            <SelectField
312	              label="Email template (all guests)"
313	              value={currentTemplate}
314	              onChange={(e) => setEventTemplate(e.target.value)}
315	            >
316	              {templates.map((t) => (
317	                <option key={t.key} value={t.key}>
318	                  {t.name}
319	                  {t.isDefault ? ' (default)' : ''}
320	                </option>
321	              ))}
322	            </SelectField>
323	          )}
324	        </Card>
325	
326	        {/* Roster */}
327	        <section>
328	          <div
329	            className="type-label-sm text-muted"
330	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
331	          >
332	            Guests · {included.length} getting a pass
333	          </div>
334	          {data.roster.length === 0 ? (
335	            <Card className="type-body text-muted">
336	              No guests on this event yet. Add attendees in Calendar, then reopen.
337	            </Card>
338	          ) : (
339	            <div className="roster">
340	              {data.roster.map((g) => (
341	                <RosterRow
342	                  key={g.email}
343	                  guest={g}
344	                  onChange={(edit) => patchGuest(g.email, edit)}
345	                />
346	              ))}
347	            </div>
348	          )}
349	        </section>
350	
351	        {/* Send result */}
352	        {send.isSuccess && <SendSummary result={send.data} />}
353	        {send.isError && (
354	          <div className="banner banner--error" role="alert">
355	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
356	            <span className="type-body">{(send.error as Error).message}</span>
357	          </div>
358	        )}
359	      </div>
360	
361	      {/* Sticky action bar */}
362	      <footer
363	        style={{
364	          padding: 'var(--space-md) var(--space-lg)',
365	          borderTop: '1px solid var(--color-outline-variant)',
366	          background: 'var(--color-surface-lowest)',
367	        }}
368	      >
369	        <AutoHideBanner show={nothingToDo}>
370	          <div
371	            className="banner banner--info"
372	            role="status"
373	            style={{ marginBottom: 'var(--space-sm)' }}
374	          >
375	            <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
376	            <span className="type-body">Up to date. No changes to send.</span>
377	          </div>
378	        </AutoHideBanner>
379	        <Button
380	          block
381	          loading={preview.isPending}
382	          disabled={!canSend}
383	          icon={<Eye size={18} strokeWidth={2} />}
384	          onClick={openReview}
385	        >
386	          {preview.isPending
387	            ? 'Loading preview…'
388	            : `${reviewLabel}${included.length ? ` (${included.length})` : ''}`}
389	        </Button>
390	        {preview.isError && (
391	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
392	            {(preview.error as Error).message}
393	          </div>
394	        )}
395	        {sentCount > 0 && !send.isPending && !nothingToDo && (
396	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
397	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
398	          </div>
399	        )}
400	      </footer>
401	
402	      {previewData && (
403	        <PreviewSheet
404	          preview={previewData.preview}
405	          recipient={previewData.recipient}
406	          totalCount={included.length}
407	          sending={send.isPending}
408	          onSend={() =>
409	            send.mutate(undefined, {
410	              onSuccess: () => {
411	                setPreviewData(null);
412	                resetEditBaseline();
413	              },
414	            })
415	          }
416	          onClose={() => setPreviewData(null)}
417	        />
418	      )}
419	    </Shell>
420	  );
421	}
422	
423	// ───────────────────────── sub-components ─────────────────────────
424	
425	/** Shows its children for ~5s each time `show` flips true, then auto-hides — an
426	 *  ephemeral notice rather than a banner that lingers. Re-shows if `show` cycles. */
427	function AutoHideBanner({ show, children }: { show: boolean; children: React.ReactNode }) {
428	  const [visible, setVisible] = useState(false);
429	  useEffect(() => {
430	    if (!show) {
431	      setVisible(false);
432	      return;
433	    }
434	    setVisible(true);
435	    const t = setTimeout(() => setVisible(false), 5000);
436	    return () => clearTimeout(t);
437	  }, [show]);
438	  return visible ? <>{children}</> : null;
439	}
440	
441	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
442	  return (
443	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
444	      <header
445	        style={{
446	          display: 'flex',
447	          alignItems: 'center',
448	          gap: 'var(--space-sm)',
449	          padding: 'var(--space-md) var(--space-lg)',
450	          borderBottom: '1px solid var(--color-outline-variant)',
451	          flex: '0 0 auto',
452	        }}
453	      >
454	        {onBack ? (
455	          <IconButton label="Back to events" onClick={onBack}>
456	            <ArrowLeft size={20} strokeWidth={2} />
457	          </IconButton>
458	        ) : (
459	          <Logo size={26} />
460	        )}
461	        <span className="type-title">Auxilio Visitor</span>
462	        <span style={{ flex: 1 }} />
463	        <AccountMenu />
464	      </header>
465	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
466	        {children}
467	      </div>
468	    </div>
469	  );
470	}
471	
472	function LoadingState({ label }: { label: string }) {
473	  return (
474	    <div
475	      style={{
476	        flex: 1,
477	        display: 'flex',
478	        flexDirection: 'column',
479	        alignItems: 'center',
480	        justifyContent: 'center',
481	        gap: 'var(--space-md)',
482	        color: 'var(--color-on-surface-variant)',
483	      }}
484	    >
485	      <span className="spinner" style={{ width: 22, height: 22 }} />
486	      <span className="type-body">{label}</span>
487	    </div>
488	  );
489	}
490	
491	function RosterSkeleton({ title }: { title?: string }) {
492	  return (
493	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
494	      <Card style={{ display: 'grid', gap: 8 }}>
495	        <span className="type-title-lg">{title || 'Loading event…'}</span>
496	        <Skeleton width="60%" />
497	      </Card>
498	      <Card style={{ display: 'grid', gap: 'var(--space-lg)' }}>
499	        {[0, 1, 2].map((i) => (
500	          <div key={i} style={{ display: 'flex', gap: 'var(--space-md)', alignItems: 'center' }}>
501	            <Skeleton width={44} height={24} radius={999} />
502	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
503	              <Skeleton width="50%" />
504	              <Skeleton width="70%" height={12} />
505	            </div>
506	          </div>
507	        ))}
508	      </Card>
509	    </div>
510	  );
511	}
512	
513	function NoticeState({
514	  title,
515	  body,
516	  onRetry,
517	  guests,
518	}: {
519	  title: string;
520	  body: string;
521	  onRetry?: () => void;
522	  guests?: string[];
523	}) {
524	  return (
525	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
526	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
527	        <span className="type-title-lg">{title}</span>
528	        <span className="type-body text-muted">{body}</span>
529	        {onRetry && (
530	          <Button
531	            variant="tonal"
532	            icon={<RefreshCw size={16} strokeWidth={2} />}
533	            onClick={onRetry}
534	            style={{ justifySelf: 'start', marginTop: 'var(--space-xs)' }}
535	          >
536	            Check again
537	          </Button>
538	        )}
539	      </Card>
540	      {guests && guests.length > 0 && (
541	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
542	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
543	            Guests detected on this event
544	          </span>
545	          {guests.map((g) => (
546	            <span key={g} className="type-body row__ellipsis">{g}</span>
547	          ))}
548	        </Card>
549	      )}
550	    </div>
551	  );
552	}
553	
554	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
555	  return (
556	    <div style={{ padding: 'var(--space-lg)' }}>
557	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
558	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
559	        <span className="type-body">{message}</span>
560	      </div>
561	      <Button variant="tonal" icon={<RefreshCw size={16} strokeWidth={2} />} onClick={onRetry}>
562	        Try again
563	      </Button>
564	    </div>
565	  );
566	}
567	
568	function SendSummary({
569	  result,
570	}: {
571	  result: import('@/lib/types').SendResponse;
572	}) {
573	  return (
574	    <div
575	      className="banner"
576	      role="status"
577	      aria-live="polite"
578	      style={{ background: 'var(--color-success-container)', color: 'var(--color-on-success-container)' }}
579	    >
580	      <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
581	      <div>
582	        <div className="type-label">
583	          {result.created.length > 0
584	            ? `${result.created.length} pass${result.created.length > 1 ? 'es' : ''} sent`
585	            : result.cancelled.length > 0
586	              ? 'Passes updated'
587	              : 'No changes'}
588	          {result.cancelled.length > 0 && ` · ${result.cancelled.length} cancelled`}
589	        </div>
590	        {result.failed.length > 0 && (
591	          <ul className="type-label-sm" style={{ margin: '4px 0 0', paddingLeft: 16 }}>
592	            {result.failed.map((f) => (
593	              <li key={f.visitorEmail}>
594	                {f.visitorEmail}: {f.reason}
595	              </li>
596	            ))}
597	          </ul>
598	        )}
599	      </div>
600	    </div>
601	  );
602	}
603	
604	function formatWhen(start: string, end?: string): string {
605	  const allDay = !start.includes('T');
606	  const s = new Date(start);
607	  const date = s.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' });
608	  if (allDay) return `${date} · All day`;
609	  const t = (d: Date) => d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
610	  return end ? `${date} · ${t(s)} to ${t(new Date(end))}` : `${date} · ${t(s)}`;
611	}
