1	/**
2	 * Typed RPC over chrome.runtime messaging. The side panel (and content script)
3	 * never touch tokens or the network directly — they send these messages and the
4	 * background worker does the work. This keeps the thin-adapter boundary: one
5	 * place holds secrets + network.
6	 */
7	import type {
8	  ActiveEvent,
9	  AuthStatus,
10	  DomEventSnapshot,
11	  DraftPatch,
12	  DraftResponse,
13	  PreviewResponse,
14	  ResolvedPerson,
15	  SendResponse,
16	  VisitDraft,
17	  VisitorEventSummary,
18	} from './types';
19	
20	export type RpcRequest =
21	  | { type: 'AUTH_STATUS' }
22	  | { type: 'AUTH_SIGN_IN' }
23	  | { type: 'AUTH_SIGN_OUT' }
24	  | { type: 'OPEN_PANEL' }
25	  | { type: 'OPEN_FOR_EVENT'; eid: string; snapshot?: DomEventSnapshot }
26	  | { type: 'FOLLOW_EVENT'; eid: string; snapshot?: DomEventSnapshot }
27	  | { type: 'RESOLVE_EVENT'; eid: string }
28	  | { type: 'DRAFT_LOAD'; event: ActiveEvent }
29	  | { type: 'RESOLVE_GUESTS'; emails: string[] }
30	  | { type: 'DRAFT_PATCH'; iCalUid: string; patch: DraftPatch }
31	  | { type: 'PREVIEW'; iCalUid: string; visitorEmail: string }
32	  | { type: 'SEND'; iCalUid: string; start?: string; end?: string }
33	  | { type: 'CANCEL_GUEST'; iCalUid: string; invitationId: string }
34	  | { type: 'LIST_VISITOR_EVENTS' }
35	  | { type: 'GET_NUDGE_TARGETS' }
36	  | { type: 'SYNC_NOW' }
37	  | { type: 'GET_PANEL_STATE' }
38	  | { type: 'NAVIGATE_TO_EVENT'; eventId?: string; eid?: string };
39	
40	/** Maps each request type to its success payload. */
41	export interface RpcResultMap {
42	  AUTH_STATUS: AuthStatus;
43	  AUTH_SIGN_IN: AuthStatus;
44	  AUTH_SIGN_OUT: { signedIn: false };
45	  OPEN_PANEL: { opened: boolean };
46	  OPEN_FOR_EVENT: { opened: boolean };
47	  FOLLOW_EVENT: { followed: boolean };
48	  RESOLVE_EVENT: ActiveEvent;
49	  DRAFT_LOAD: DraftResponse;
50	  RESOLVE_GUESTS: Record<string, ResolvedPerson>;
51	  DRAFT_PATCH: VisitDraft;
52	  PREVIEW: PreviewResponse;
53	  SEND: SendResponse;
54	  CANCEL_GUEST: { invitationId: string; cancelled: boolean };
55	  LIST_VISITOR_EVENTS: VisitorEventSummary[];
56	  GET_NUDGE_TARGETS: VisitorEventSummary[];
57	  SYNC_NOW: { synced: boolean };
58	  GET_PANEL_STATE: { open: boolean };
59	  NAVIGATE_TO_EVENT: { navigated: boolean };
60	}
61	
62	export type RpcResponse<T> =
63	  | { ok: true; data: T }
64	  | { ok: false; error: string; status?: number; needsAuth?: boolean };
65	
66	export class RpcError extends Error {
67	  constructor(
68	    message: string,
69	    readonly status?: number,
70	    readonly needsAuth?: boolean,
71	  ) {
72	    super(message);
73	    this.name = 'RpcError';
74	  }
75	}
76	
77	/** Side-panel-side caller: throws RpcError on failure, returns typed data. */
78	export async function rpc<K extends RpcRequest['type']>(
79	  msg: Extract<RpcRequest, { type: K }>,
80	): Promise<RpcResultMap[K]> {
81	  const res = (await chrome.runtime.sendMessage(msg)) as
82	    | RpcResponse<RpcResultMap[K]>
83	    | undefined;
84	  if (!res) throw new RpcError('No response from background worker');
85	  if (!res.ok) throw new RpcError(res.error, res.status, res.needsAuth);
86	  return res.data;
87	}
88	
89	/** storage.session key holding the pending event id (set by background on the
90	 *  content-script button click, read reactively by the side panel). */
91	export const ACTIVE_EID_KEY = 'auxilio.activeEid';
92	
93	/** storage.session key holding the DOM snapshot for the pending event — lets the
94	 *  panel paint instantly + handle the unsaved (no-API) case. */
95	export const ACTIVE_SNAPSHOT_KEY = 'auxilio.activeSnapshot';
96	
