1041	      // longer a visitor event) → purge any optimistic guess so a deleted
1042	      // event can't keep nudging (or reopen the panel for a ghost event).
1043	      for (const id of cancelled) dropOptimistic(id);
1044	      // Drop optimistic entries the real sync now covers.
1045	      for (const t of targets) dropOptimistic(t.eventId);
1046	      render();
1047	    },
1048	    addOptimistic(s: VisitorEventSummary) {
1049	      optimistic.set(s.eventId, s);
1050	      const existing = optimisticTimers.get(s.eventId);
1051	      if (existing) clearTimeout(existing);
1052	      optimisticTimers.set(
1053	        s.eventId,
1054	        setTimeout(() => {
1055	          optimistic.delete(s.eventId);
1056	          optimisticTimers.delete(s.eventId);
1057	          render();
1058	        }, OPTIMISTIC_TTL),
1059	      );
1060	      render();
1061	    },
1062	    setPanelOpen(open: boolean) {
