1083	 * lapse (the user was connected but a silent token renew failed). Without it the
1084	 * whole nudge mechanism goes dark silently. "Reconnect" opens the side panel onto
1085	 * the sign-in gate. Hidden while the panel is open (the gate is right there).
1086	 */
1087	function mountReconnect(onReconnect: () => void) {
1088	  const host = document.createElement('div');
1089	  // Sits just below the nudge banner's slot; pointer-events:none while hidden so
1090	  // it never swallows clicks on the Calendar UI beneath it.
