1	/**
2	 * Engine client (background only) for the office-ops-engine /addon/* routes.
3	 * Reuses the existing contract verbatim — no engine changes. Authenticated with
4	 * the host's Google id_token (Bearer). Always sends the canonical iCalUid so the
5	 * extension converges on the same calendar_event_links row as .ics/OAuth/add-on.
6	 */
7	import { ADDON_API } from './config';
8	import type {
9	  ActiveEvent,
10	  DraftPatch,
11	  DraftResponse,
12	  PreviewResponse,
13	  SendResponse,
14	  VisitDraft,
15	} from './types';
16	
17	export class EngineError extends Error {
18	  constructor(
19	    message: string,
20	    readonly status: number,
21	  ) {
22	    super(message);
23	    this.name = 'EngineError';
24	  }
25	}
26	
27	async function call<T>(
28	  path: string,
29	  method: string,
30	  idToken: string,
31	  body?: unknown,
32	): Promise<T> {
33	  const url = `${ADDON_API}/${path}`;
34	  const started = Date.now();
35	  // Abort hung requests so the UI errors instead of spinning forever
36	  // (bifrost dev cold-starts + MV3 service-worker lifetime can stall a fetch).
37	  const ctrl = new AbortController();
38	  const timeout = setTimeout(() => ctrl.abort(), 20_000);
39	  console.log('[auxilio] engine →', method, url);
40	  let res: Response;
41	  try {
42	    res = await fetch(url, {
43	      method,
44	      headers: {
45	        'Content-Type': 'application/json',
46	        Authorization: `Bearer ${idToken}`,
47	      },
48	      body: body ? JSON.stringify(body) : undefined,
49	      signal: ctrl.signal,
50	    });
51	  } catch (err) {
52	    if ((err as Error).name === 'AbortError') {
53	      throw new EngineError(
54	        `Engine did not respond within 20s (${url}). Is it reachable?`,
55	        0,
56	      );
57	    }
58	    throw new EngineError(
59	      `Could not reach the engine (${(err as Error).message}). Check WXT_ENGINE_URL / host_permissions.`,
60	      0,
61	    );
62	  } finally {
63	    clearTimeout(timeout);
64	  }
65	  const text = await res.text();
66	  console.log('[auxilio] engine ←', res.status, `${Date.now() - started}ms`, text.slice(0, 200));
67	  let data: { error?: string } = {};
68	  try {
69	    data = text ? JSON.parse(text) : {};
70	  } catch {
71	    if (!res.ok) throw new EngineError(`Engine error ${res.status}: ${text.slice(0, 140)}`, res.status);
72	  }
73	  if (!res.ok) {
74	    throw new EngineError(data?.error ?? `Request failed (${res.status})`, res.status);
75	  }
76	  return data as T;
77	}
78	
79	export const engine = {
80	  loadDraft: (idToken: string, ev: ActiveEvent) =>
81	    call<DraftResponse>('draft', 'POST', idToken, {
82	      iCalUid: ev.iCalUid,
83	      providerEventId: ev.providerEventId,
84	      title: ev.title,
85	      attendees: ev.attendees,
86	      start: ev.start,
87	      end: ev.end,
88	      location: ev.location,
89	      organizerEmail: ev.organizerEmail,
90	    }),
91	
92	  patchDraft: (idToken: string, iCalUid: string, patch: DraftPatch) =>
93	    call<VisitDraft>('draft', 'PATCH', idToken, { iCalUid, patch }),
94	
95	  preview: (idToken: string, iCalUid: string, visitorEmail: string) =>
96	    call<PreviewResponse>('preview', 'POST', idToken, { iCalUid, visitorEmail }),
97	
98	  send: (idToken: string, iCalUid: string, start?: string, end?: string) =>
99	    call<SendResponse>('send', 'POST', idToken, { iCalUid, start, end }),
100	
101	  /** Read-only batch check: which of these events already have an active pass
102	   *  (through any surface). Lets the background poll suppress cross-channel nudges.
103	   *  Side-effect-free on the engine — safe to poll. */
104	  status: (idToken: string, iCalUids: string[]) =>
105	    call<{ active: string[] }>('status', 'POST', idToken, { iCalUids }),
106	
107	  cancelGuest: (idToken: string, iCalUid: string, invitationId: string) =>
108	    call<{ invitationId: string; cancelled: boolean }>(
109	      'cancel-guest',
110	      'POST',
111	      idToken,
112	      { iCalUid, invitationId },
113	    ),
114	
115	  connectCalendar: (idToken: string, code: string, redirectUri: string) =>
116	    call<{ connected: boolean }>('connect-calendar', 'POST', idToken, { code, redirectUri }),
117	};
