691	export async function patchDraft(iCalUid: string, patch: DraftPatch | undefined): Promise<VisitDraft | null> {
692	  const draft = await getDraft(iCalUid);
693	  if (!draft) return null;
694	  if (patch?.location !== undefined) draft.location = patch.location;
695	  for (const gp of patch?.guests ?? []) {
696	    const guest = draft.roster.find((g) => g.email.toLowerCase() === gp.email.toLowerCase());
697	    if (!guest) continue;
698	    if (gp.include !== undefined) guest.include = gp.include;
699	    if (gp.name !== undefined) guest.name = gp.name;
700	    if (gp.phone !== undefined) guest.phone = gp.phone;
701	    if (gp.passTemplateKey !== undefined) guest.passTemplateKey = gp.passTemplateKey;
702	    if (gp.emailTemplateKey !== undefined) guest.emailTemplateKey = gp.emailTemplateKey;
703	  }
704	  await upsertDraft(draft);
705	  return draft;
706	}
707	
708	/** Record created invites back onto the draft (status + invitationId) and optionally new times. */
709	export async function markMaterialized(
710	  iCalUid: string,
711	  passes: { visitorEmail: string; invitationId: string }[],
712	  times?: { eventStart?: string; eventEnd?: string },
713	): Promise<void> {
714	  const draft = await getDraft(iCalUid);
715	  if (!draft) return;
716	  for (const pass of passes) {
717	    const guest = draft.roster.find((g) => g.email.toLowerCase() === pass.visitorEmail.toLowerCase());
718	    if (guest) {
719	      guest.invitationId = pass.invitationId;
720	      guest.status = 'sent';
721	    }
722	  }
723	  draft.materialized = true;
724	  if (times?.eventStart !== undefined) draft.eventStart = times.eventStart;
725	  if (times?.eventEnd !== undefined) draft.eventEnd = times.eventEnd;
726	  await upsertDraft(draft);
727	}
728	
729	// ─── Materialize ──────────────────────────────────────────────
730	
731	/**
732	 * Create one visitor invite per INCLUDED guest, honoring the host's overrides.
733	 * Reuses `createVisitorInvite` (the shared cross-channel entry) — no logic fork.
734	 * Caller is responsible for cancelling any prior invites and writing the
735	 * `calendar_event_links` ledger row (so dedup/reschedule converge).
736	 */
737	export async function materializeDraft(
738	  draft: VisitDraft,
739	  opts: { hostName?: string; rescheduled?: boolean } = {},
740	): Promise<{ invitationIds: string[]; passes: PassResult[] }> {
741	  // Pass duration must equal the event window — never guess (decision 2026-06-17).
742	  const window = resolveEventWindow(draft);
743	  if (!window) {
744	    console.warn(`[VisitDraft] materialize skipped for ${draft.iCalUid}: ${EVENT_TIME_MISSING}`);
745	    return { invitationIds: [], passes: [] };
746	  }
747	  const { start, end } = window;
748	
749	  const resolvedHost = draft.hostEmail
750	    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
751	    : null;
752	  // Prefer the Workspace-resolved name; only fall back to opts.hostName when it's
753	  // a real name (not the email the ID token gives us). Never show the email.
754	  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
755	  // On a reschedule, the guest already had a pass → frame the new one as updated.
756	  const emailOverride = opts.rescheduled ? { ...RESCHEDULED_EMAIL_OVERRIDE } : undefined;
757	
758	  const passes: PassResult[] = [];
759	  for (const guest of draft.roster) {
760	    if (!guest.include || !guest.email) continue;
761	    const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
