340	// ─── Edit an existing invite (Google-Sheet edit-sync) ─────────
341	
342	/**
343	 * Thrown by `updateVisitorInvite` when the invite can't be edited any more
344	 * (already used / cancelled / rejected / expired). Callers surface the message
345	 * and route the admin to the dashboard instead.
346	 */
347	export class InviteNotEditableError extends Error {
348	  readonly code = 'INVITE_NOT_EDITABLE';
349	  constructor(message: string) {
350	    super(message);
351	    this.name = 'InviteNotEditableError';
352	  }
353	}
354	
355	export interface VisitorInviteUpdateInput {
356	  visitorName?: string;
357	  visitorPhone?: string;
358	  visitorEmail?: string;
359	  purpose?: string;
360	  /** Primary host email (re-resolved + stakeholder replaced when changed). */
361	  primaryHostEmail?: string;
362	  /** Full desired CC-host set (stakeholders reconciled when changed). */
363	  ccHostEmails?: string[];
364	  /** IST date `YYYY-MM-DD`. */
365	  expectedDate?: string;
366	  /** Start time `HH:MM` (24h). */
367	  startTime?: string;
368	  /** End time `HH:MM` (24h). */
369	  endTime?: string;
370	}
371	
372	export interface UpdateVisitorInviteResult {
373	  changed: boolean;
374	  changedFields: string[];
375	  emailResent: boolean;
376	  emailError?: string;
377	}
378	
379	const _norm = (v?: string | null): string => (v ?? '').trim();
380	const _hhmm = (iso?: string | null): string => (iso ? formatTimeInIST(iso).slice(0, 5) : '');
381	
382	async function getStakeholderEmailsByRole(invitationId: string, role: string): Promise<string[]> {
383	  const db = getOptionalPostgresDb();
384	  if (!db) return [];
385	  const rows = await db
386	    .select({ email: visitorInvitationStakeholders.email })
387	    .from(visitorInvitationStakeholders)
388	    .where(and(
389	      eq(visitorInvitationStakeholders.invitationId, invitationId),
390	      eq(visitorInvitationStakeholders.role, role),
391	    ));
392	  return rows
393	    .map((r) => _norm(r.email).toLowerCase())
394	    .filter(Boolean);
395	}
396	
397	/**
398	 * Apply an edit to an already-created invite (the Google-Sheet edit-sync path).
399	 *
400	 * - Diffs each field against the stored invite; if nothing changed it is a
401	 *   no-op (no write, no email) — this is what keeps a routine re-Process from
402	 *   spuriously re-emailing guests.
403	 * - Guest-facing changes (name / email / purpose / date / time / host) resend
404	 *   the pass email with the "rescheduled / updated" copy.
405	 * - Host changes re-resolve the contact and reconcile stakeholders.
406	 * - Throws `InviteNotEditableError` for used/cancelled/rejected/expired invites.
407	 */
408	export async function updateVisitorInvite(
409	  invitationId: string,
410	  input: VisitorInviteUpdateInput,
411	): Promise<UpdateVisitorInviteResult> {
412	  const invitation = await getInvitationById(invitationId);
413	  if (!invitation) throw new Error('Invitation not found in system.');
414	
415	  if (invitation.token_used) {
416	    throw new InviteNotEditableError('This pass has already been used — edit it in the dashboard, not the sheet.');
417	  }
418	  if (['cancelled', 'rejected', 'expired'].includes(invitation.approval_status)) {
419	    throw new InviteNotEditableError(`This pass is ${invitation.approval_status} — re-invite from a new row instead of editing.`);
420	  }
421	
422	  const changedFields: string[] = [];
423	  const fieldUpdates: UpdateInvitationFields = {};
424	
425	  if (input.visitorName !== undefined && _norm(input.visitorName) !== _norm(invitation.visitor_name)) {
426	    fieldUpdates.visitorName = _norm(input.visitorName);
427	    changedFields.push('name');
428	  }
429	  if (input.visitorPhone !== undefined && _norm(input.visitorPhone) !== _norm(invitation.visitor_phone)) {
430	    fieldUpdates.visitorPhone = _norm(input.visitorPhone) || null;
431	    changedFields.push('phone');
432	  }
433	  if (input.visitorEmail !== undefined && _norm(input.visitorEmail) !== _norm(invitation.visitor_email)) {
434	    fieldUpdates.visitorEmail = _norm(input.visitorEmail) || null;
435	    changedFields.push('email');
436	  }
437	  if (input.purpose !== undefined && _norm(input.purpose) !== _norm(invitation.purpose)) {
438	    fieldUpdates.purpose = _norm(input.purpose) || null;
439	    changedFields.push('purpose');
440	  }
441	
442	  // Date / time → recompute valid_from / valid_until. Compare on the IST HH:MM
443	  // projection of the stored ISO timestamps so a re-Process doesn't false-diff.
444	  const currentStart = _hhmm(invitation.valid_from);
445	  const currentEnd = _hhmm(invitation.valid_until);
446	  const dateChanged = input.expectedDate !== undefined && _norm(input.expectedDate) !== _norm(invitation.expected_date);
447	  const startChanged = input.startTime !== undefined && _norm(input.startTime) !== currentStart;
448	  const endChanged = input.endTime !== undefined && _norm(input.endTime) !== currentEnd;
449	
450	  const effectiveDate = input.expectedDate !== undefined ? _norm(input.expectedDate) : invitation.expected_date;
451	  const effectiveStart = input.startTime !== undefined ? _norm(input.startTime) : currentStart;
452	  const effectiveEnd = input.endTime !== undefined ? _norm(input.endTime) : currentEnd;
453	
454	  if (dateChanged) {
455	    fieldUpdates.expectedDate = effectiveDate;
456	    changedFields.push('date');
457	  }
458	  if (dateChanged || startChanged) {
459	    fieldUpdates.expectedTime = effectiveStart || null;
460	    fieldUpdates.validFrom = effectiveStart
461	      ? (combineISTDateAndTimeToISO(effectiveDate, effectiveStart) ?? undefined)
462	      : (startOfISTDayToISO(effectiveDate) ?? undefined);
463	    if (startChanged) changedFields.push('start time');
464	  }
465	  if (dateChanged || endChanged) {
466	    fieldUpdates.validUntil = effectiveEnd
467	      ? (combineISTDateAndTimeToISO(effectiveDate, effectiveEnd) ?? undefined)
468	      : (computeExpiry('invited', effectiveDate));
469	    if (endChanged) changedFields.push('end time');

