export class InviteNotEditableError extends Error {
  readonly code = 'INVITE_NOT_EDITABLE';
  constructor(message: string) {
    super(message);
    this.name = 'InviteNotEditableError';
  }
}

export interface VisitorInviteUpdateInput {
  visitorName?: string;
  visitorPhone?: string;
  visitorEmail?: string;
  purpose?: string;
  /** Primary host email (re-resolved + stakeholder replaced when changed). */
  primaryHostEmail?: string;
  /** Full desired CC-host set (stakeholders reconciled when changed). */
  ccHostEmails?: string[];
  /** IST date `YYYY-MM-DD`. */
  expectedDate?: string;
  /** Start time `HH:MM` (24h). */
  startTime?: string;
  /** End time `HH:MM` (24h). */
  endTime?: string;
}

export interface UpdateVisitorInviteResult {
  changed: boolean;
  changedFields: string[];
  emailResent: boolean;
  emailError?: string;
}

const _norm = (v?: string | null): string => (v ?? '').trim();
const _hhmm = (iso?: string | null): string => (iso ? formatTimeInIST(iso).slice(0, 5) : '');

async function getStakeholderEmailsByRole(invitationId: string, role: string): Promise<string[]> {
  const db = getOptionalPostgresDb();
  if (!db) return [];
  const rows = await db
    .select({ email: visitorInvitationStakeholders.email })
    .from(visitorInvitationStakeholders)
    .where(and(
      eq(visitorInvitationStakeholders.invitationId, invitationId),
      eq(visitorInvitationStakeholders.role, role),
    ));
  return rows
    .map((r) => _norm(r.email).toLowerCase())
    .filter(Boolean);
}

/**
 * Apply an edit to an already-created invite (the Google-Sheet edit-sync path).
 *
 * - Diffs each field against the stored invite; if nothing changed it is a
 *   no-op (no write, no email) — this is what keeps a routine re-Process from
 *   spuriously re-emailing guests.
 * - Guest-facing changes (name / email / purpose / date / time / host) resend
 *   the pass email with the "rescheduled / updated" copy.
 * - Host changes re-resolve the contact and reconcile stakeholders.
 * - Throws `InviteNotEditableError` for used/cancelled/rejected/expired invites.
 */
export async function updateVisitorInvite(
  invitationId: string,
  input: VisitorInviteUpdateInput,
): Promise<UpdateVisitorInviteResult> {
  const invitation = await getInvitationById(invitationId);
  if (!invitation) throw new Error('Invitation not found in system.');

  if (invitation.token_used) {
    throw new InviteNotEditableError('This pass has already been used — edit it in the dashboard, not the sheet.');
  }
  if (['cancelled', 'rejected', 'expired'].includes(invitation.approval_status)) {
    throw new InviteNotEditableError(`This pass is ${invitation.approval_status} — re-invite from a new row instead of editing.`);
  }

  const changedFields: string[] = [];
  const fieldUpdates: UpdateInvitationFields = {};

  if (input.visitorName !== undefined && _norm(input.visitorName) !== _norm(invitation.visitor_name)) {
    fieldUpdates.visitorName = _norm(input.visitorName);
    changedFields.push('name');
  }
  if (input.visitorPhone !== undefined && _norm(input.visitorPhone) !== _norm(invitation.visitor_phone)) {
    fieldUpdates.visitorPhone = _norm(input.visitorPhone) || null;
    changedFields.push('phone');
  }
  if (input.visitorEmail !== undefined && _norm(input.visitorEmail) !== _norm(invitation.visitor_email)) {
    fieldUpdates.visitorEmail = _norm(input.visitorEmail) || null;
    changedFields.push('email');
  }
  if (input.purpose !== undefined && _norm(input.purpose) !== _norm(invitation.purpose)) {
    fieldUpdates.purpose = _norm(input.purpose) || null;
    changedFields.push('purpose');
  }

  // Date / time → recompute valid_from / valid_until. Compare on the IST HH:MM
  // projection of the stored ISO timestamps so a re-Process doesn't false-diff.
  const currentStart = _hhmm(invitation.valid_from);
  const currentEnd = _hhmm(invitation.valid_until);
  const dateChanged = input.expectedDate !== undefined && _norm(input.expectedDate) !== _norm(invitation.expected_date);
  const startChanged = input.startTime !== undefined && _norm(input.startTime) !== currentStart;
  const endChanged = input.endTime !== undefined && _norm(input.endTime) !== currentEnd;

  const effectiveDate = input.expectedDate !== undefined ? _norm(input.expectedDate) : invitation.expected_date;
  const effectiveStart = input.startTime !== undefined ? _norm(input.startTime) : currentStart;
  const effectiveEnd = input.endTime !== undefined ? _norm(input.endTime) : currentEnd;

  if (dateChanged) {
    fieldUpdates.expectedDate = effectiveDate;
    changedFields.push('date');
  }
  if (dateChanged || startChanged) {
    fieldUpdates.expectedTime = effectiveStart || null;
    fieldUpdates.validFrom = effectiveStart
      ? (combineISTDateAndTimeToISO(effectiveDate, effectiveStart) ?? undefined)
      : (startOfISTDayToISO(effectiveDate) ?? undefined);
    if (startChanged) changedFields.push('start time');
  }
  if (dateChanged || endChanged) {
    fieldUpdates.validUntil = effectiveEnd
      ? (combineISTDateAndTimeToISO(effectiveDate, effectiveEnd) ?? undefined)
      : (computeExpiry('invited', effectiveDate));
    if (endChanged) changedFields.push('end time');

