export interface ApplyResult {
  /** Every currently-active invitation id (for the ledger). */
  invitationIds: string[];
  /** Guests whose pass was created in THIS apply. */
  created: PassResult[];
  /** Guests whose pass was cancelled in THIS apply. */
  cancelled: { visitorEmail: string; invitationId: string }[];
  /** Guests we tried to send but couldn't (e.g. event time in the past). */
  failed: { visitorEmail: string; reason: string }[];
  draft: VisitDraft;
}

/**
 * Reconcile the live passes to match the roster's include toggles (plan §1):
 *   include=true  & no active pass → create
 *   include=false & active pass    → cancel
 *   include=true  & active pass     → keep (a same-time edit; event-move reissue is
 *                                     handled separately in calendar-ingest)
 * Persists the draft (status + invitationId per guest, materialized flag). The
 * caller writes the `calendar_event_links` ledger from `invitationIds`.
 */
export async function applyDraft(draft: VisitDraft, opts: { hostName?: string } = {}): Promise<ApplyResult> {
  // Pass duration must equal the event window — never guess (decision 2026-06-17).
  // When the times are unavailable we still process cancellations, but refuse to
  // CREATE a pass with a wrong duration; those guests are reported as failed.
  const window = resolveEventWindow(draft);
  const start = window?.start;
  const end = window?.end;
  const resolvedHost = draft.hostEmail
    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
    : null;
  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);

  const created: PassResult[] = [];
  const cancelled: { visitorEmail: string; invitationId: string }[] = [];
  const failed: { visitorEmail: string; reason: string }[] = [];

  for (const guest of draft.roster) {
    const hasActivePass = guest.status === 'sent' && !!guest.invitationId;

    if (guest.include && !hasActivePass) {
      if (!start || !end) {
        // No reliable event window → don't issue a wrong-duration pass.
        failed.push({ visitorEmail: guest.email, reason: EVENT_TIME_MISSING });
        continue;
      }
      const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
      try {
        const result = await createVisitorInvite({
          visitorName,
          visitorEmail: guest.email,
          visitorPhone: guest.phone || undefined,
          purpose: draft.title,
          hostEmail: draft.hostEmail,
          hostEmployeeId: resolvedHost?.staff?.id,
          hostEmployeeName: hostName ?? draft.hostEmail,
          expectedDate: istDate(start),
          expectedTime: istTime(start),
          validFrom: start.toISOString(),
          validUntil: end.toISOString(),
          emailTemplateKey: guest.emailTemplateKey,
          passTemplateKey: guest.passTemplateKey,
          invitedVia: 'calendar',
          invitedBy: draft.hostEmail,
          batchId: draft.iCalUid,
          approvalTier: 'invited',
          allowInternalColleague: true, // host-included guest = override (F2)
        });
        guest.invitationId = result.invitationId;
        guest.status = 'sent';
        created.push({ visitorEmail: guest.email, visitorName, invitationId: result.invitationId, passUrl: result.qrUrl, status: 'sent' });
      } catch (err) {
        const reason = err instanceof Error ? err.message : String(err);
        console.warn(`[VisitDraft] apply-create for ${guest.email} failed:`, reason);
        failed.push({ visitorEmail: guest.email, reason });
      }
    } else if (!guest.include && hasActivePass) {
      const id = guest.invitationId as string;
      const ok = await cancelInvitationById(id).catch((e) => {
        console.warn(`[VisitDraft] apply-cancel ${id} failed:`, e);
        return false;
      });
      if (ok) await notifyInviteCancelled(id, { cancelledBy: hostName, reason: 'The host cancelled your visitor pass.' });
      cancelled.push({ visitorEmail: guest.email, invitationId: id });
      guest.status = 'cancelled';
      guest.invitationId = undefined;
    }
  }

