if ((pathname === '/api/visitor/calendar/addon/send' || pathname === '/api/visitor/calendar/addon/apply') && method === 'POST') {
  const body = await readBodyJson(req);
  const iCalUid = String(body.iCalUid ?? '').trim();
  const draft = iCalUid ? await getDraft(iCalUid) : null;
  if (!draft) { json(res, 404, { error: 'draft not found' }); return true; }
  // Self-correct the event window from the times the card re-resolves at send.
  // The draft-open's time fetch (Calendar.Events.get) is flaky on a just-created
  // event, so the stored draft can lack start/end → applyDraft would fail every
  // guest with EVENT_TIME_MISSING. Trust fresh times when the card provides them.
  if (body.start) draft.eventStart = String(body.start);
  if (body.end) draft.eventEnd = String(body.end);
  const result = await applyDraft(draft, { hostName: identity.name });
  // Record the ledger from the active set; draft_authoritative so passive
  // producers reissue/cancel from the curated roster on move/delete.
  await recordDraftMaterialization({
    iCalUid,
    providerEventId: draft.providerEventId,
    organizerEmail: identity.email,
    invitationIds: result.invitationIds,
    eventStart: draft.eventStart ?? null,
    eventEnd: draft.eventEnd ?? null,
  });
  json(res, 200, {
    iCalUid,
    created: result.created,
    cancelled: result.cancelled,
    failed: result.failed,
    activeCount: result.invitationIds.length,
    draft: result.draft,
  });
  return true;
}

// POST /addon/cancel-guest — cancel one guest's invite.
if (pathname === '/api/visitor/calendar/addon/cancel-guest' && method === 'POST') {
  const body = await readBodyJson(req);
  const invitationId = String(body.invitationId ?? '').trim();
  if (!invitationId) { json(res, 422, { error: 'invitationId required' }); return true; }
  const cancelled = await cancelInvitationById(invitationId).catch(() => false);
  json(res, 200, { invitationId, cancelled });
  return true;
}

// POST /addon/connect-calendar — one-consent calendar connect from the Chrome
// extension's hybrid sign-in. Exchanges the auth code for a refresh token so the
// background poll keeps passes in sync when the panel is closed. Best-effort:
// always 200 (sign-in must not fail on this); the connectUrl CTA is the fallback.
if (pathname === '/api/visitor/calendar/addon/connect-calendar' && method === 'POST') {
  if (!isAuxilioExtensionOAuthConfigured()) {
    json(res, 200, { connected: false });
    return true;
  }
  const body = await readBodyJson(req);
  const code = String(body.code ?? '').trim();
  const redirectUri = String(body.redirectUri ?? '').trim();
  if (!code || !redirectUri) { json(res, 422, { error: 'code and redirectUri required' }); return true; }

  // Never downgrade a host who already has offline access (e.g. Slack rw connect) —
  // any connected refresh token already powers the read poll. (D7)
  const existing = await getCalendarConnection(identity.email).catch(() => null);

