const CACHE_KEY = 'auxilio.peopleCache';
const CACHE_TTL_MS = 7 * 24 * 60 * 60 * 1000; // names/photos change rarely
const CACHE_MAX = 1000;

type CacheEntry = { person: ResolvedPerson | null; at: number };

